metadata_path = 'var_functions.query_db:28'
with open(metadata_path, 'r') as f:
    europe_metadata = json.load(f)

# Read articles data from file
articles_path = 'var_functions.query_db:30'
with open(articles_path, 'r') as f:
    articles_data = json.load(f)

# Create article lookup
articles_dict = {}
for art in articles_data:
    articles_dict[str(art['article_id'])] = {
        'title': art['title'],
        'description': art['description']
    }

# Filter Europe articles for 2010-2020
europe_articles_2010_2020 = []
for meta in europe_metadata:
    year = int(meta['publication_date'].split('-')[0])
    if 2010 <= year <= 2020:
        article_id = str(meta['article_id'])
        if article_id in articles_dict:
            europe_articles_2010_2020.append({
                'article_id': article_id,
                'year': year,
                'title': articles_dict[article_id]['title'],
                'description': articles_dict[article_id]['description']
            })

print('__RESULT__:')
print(json.dumps({
    'count': len(europe_articles_2010_2020),
    'sample': europe_articles_2010_2020[:3]
}))

